async (params, browser) => {
  // Open MyFitnessPal
  await browser.open(`https://www.myfitnesspal.com/food/diary?date=${params.date}`)

  // Wait for page
  await browser.waitForSelector('.diary-table, [class*="diary"], table, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const meals = {}; let currentMeal = ''; document.querySelectorAll('.diary-table tr, [class*="diary"] tr, table tr').forEach(row => { const mealHeader = row.querySelector('.meal_header, th[class*="meal"], td.first.alt'); if (mealHeader) { currentMeal = mealHeader.textContent?.trim() || ''; meals[currentMeal] = []; return; } if (currentMeal) { const nameEl = row.querySelector('a.js-show-food-diary, td.first a, [class*="food-name"]'); const calEl = row.querySelector('td.delete + td, [class*="calorie"]'); if (nameEl) meals[currentMeal].push({ food: nameEl.textContent?.trim() || '', calories: calEl?.textContent?.trim() || '' }); } }); return { date: '' + params.date + '', meals, url: window.location.href };`)

  return result
}
